using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidences { get; set; } = new();
}

public class EvaluationResult
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetric
{
    public string Class { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext;
    private ITransformer _model = null!;
    private PredictionEngine<TicketData, TicketPrediction> _predictionEngine = null!;
    private string[] _classLabels = [];
    private EvaluationResult _evaluationResult = new();

    public EvaluationResult EvaluationMetrics => _evaluationResult;

    public TicketModelService()
    {
        _mlContext = new MLContext(seed: 42);
    }

    public void TrainAndEvaluate(string dataPath)
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build the pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validate on small data for more reliable metrics
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(
            dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        // Pick the best fold's model
        var bestRun = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();

        _evaluationResult = new EvaluationResult
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
            PerClassMetrics = bestRun.Metrics.PerClassLogLoss
                .Select((logLoss, i) => new PerClassMetric
                {
                    Class = $"Class_{i}",
                    Precision = i < bestRun.Metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? bestRun.Metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < bestRun.Metrics.ConfusionMatrix.PerClassRecall.Count
                        ? bestRun.Metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                    F1Score = CalculateF1(
                        i < bestRun.Metrics.ConfusionMatrix.PerClassPrecision.Count
                            ? bestRun.Metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                        i < bestRun.Metrics.ConfusionMatrix.PerClassRecall.Count
                            ? bestRun.Metrics.ConfusionMatrix.PerClassRecall[i] : 0)
                }).ToArray()
        };

        // Train the final model on all data for production use
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract the actual label names from the trained model's key-to-value mapping
        var schema = _model.GetOutputSchema(dataView.Schema);
        if (schema.TryGetColumnIndex("Label", out int labelCol))
        {
            var labelColumn = schema[labelCol];
            var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
            if (keyType != null)
            {
                var keyValues = new VBuffer<ReadOnlyMemory<char>>();
                labelColumn.GetKeyValues(ref keyValues);
                _classLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

                // Update per-class metric names
                for (int i = 0; i < _evaluationResult.PerClassMetrics.Length && i < _classLabels.Length; i++)
                {
                    _evaluationResult.PerClassMetrics[i].Class = _classLabels[i];
                }
            }
        }

        if (_classLabels.Length == 0)
        {
            _classLabels = ["Billing", "General", "Technical"];
        }
    }

    public TicketPredictionResult Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidences = new Dictionary<string, float>();
        for (int i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
        {
            confidences[_classLabels[i]] = prediction.Score[i];
        }

        return new TicketPredictionResult
        {
            PredictedCategory = prediction.Category,
            Confidences = confidences
        };
    }

    private static double CalculateF1(double precision, double recall) =>
        precision + recall == 0 ? 0 : 2 * (precision * recall) / (precision + recall);
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketModelService _modelService;

    public TicketClassifierController(TicketModelService modelService)
    {
        _modelService = modelService;
    }

    [HttpPost("predict")]
    public ActionResult<TicketPredictionResult> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _modelService.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResult> GetMetrics()
    {
        return Ok(_modelService.EvaluationMetrics);
    }
}

