using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<TicketModelService>();

var app = builder.Build();

// Train the model at startup
var modelService = app.Services.GetRequiredService<TicketModelService>();
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "tickets.csv");
modelService.TrainAndEvaluate(dataPath);

var metrics = modelService.EvaluationMetrics;
app.Logger.LogInformation(
    "Model trained. Macro Accuracy: {MacroAccuracy:P2}, Micro Accuracy: {MicroAccuracy:P2}",
    metrics.MacroAccuracy, metrics.MicroAccuracy);

app.MapControllers();
app.Run();

